#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <omp.h>

#define NX 4096
#define NY 4096
#define STEPS 1000

int main() {
    float *A = (float*)malloc(NX * NY * sizeof(float));
    float *B = (float*)malloc(NX * NY * sizeof(float));

    // Initialize arrays
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < NX; i++) {
        for (int j = 0; j < NY; j++) {
            A[i * NY + j] = 0.0f;
            B[i * NY + j] = 0.0f;
        }
    }

    // Set boundary conditions
    #pragma omp parallel for
    for (int i = 0; i < NX; i++) {
        A[i * NY + 0] = 1.0f;
        A[i * NY + (NY - 1)] = 1.0f;
        B[i * NY + 0] = 1.0f;
        B[i * NY + (NY - 1)] = 1.0f;
    }
    #pragma omp parallel for
    for (int j = 0; j < NY; j++) {
        A[0 * NY + j] = 1.0f;
        A[(NX - 1) * NY + j] = 1.0f;
        B[0 * NY + j] = 1.0f;
        B[(NX - 1) * NY + j] = 1.0f;
    }

    for (int step = 0; step < STEPS; step++) {
        #pragma omp parallel for collapse(2)
        for (int i = 1; i < NX - 1; i++) {
            for (int j = 1; j < NY - 1; j++) {
                B[i * NY + j] = 0.25f * (A[(i - 1) * NY + j] + A[(i + 1) * NY + j] +
                                         A[i * NY + (j - 1)] + A[i * NY + (j + 1)]);
            }
        }

        #pragma omp parallel for collapse(2)
        for (int i = 1; i < NX - 1; i++) {
            for (int j = 1; j < NY - 1; j++) {
                A[i * NY + j] = 0.25f * (B[(i - 1) * NY + j] + B[(i + 1) * NY + j] +
                                         B[i * NY + (j - 1)] + B[i * NY + (j + 1)]);
            }
        }
    }

    // Print a checksum to verify correctness
    double sum = 0.0;
    #pragma omp parallel for reduction(+:sum)
    for (int i = 0; i < NX * NY; i++) {
        sum += A[i];
    }
    printf("Checksum: %f\n", sum);

    free(A);
    free(B);
    return 0;
}
